import gradio as gr
import mysql.connector

# Function to fetch details from MySQL database based on PR_Number or Status
def fetch_details(pr_input, status_filter):
    try:
        connection = mysql.connector.connect(
            host='localhost',
            database='records',
            user='root',
            password='Nikki@1234'
        )

        if connection.is_connected():
            cursor = connection.cursor(dictionary=True)

            if pr_input:  # If PR_Number is provided, ignore status filter
                fetch_query = "SELECT * FROM PR_Details WHERE PR_Number = %s"
                cursor.execute(fetch_query, (pr_input,))
            else:  # If Status filter is selected, fetch records by status
                fetch_query = "SELECT * FROM PR_Details WHERE status = %s"
                cursor.execute(fetch_query, (status_filter,))

            records = cursor.fetchall()
            cursor.close()
            connection.close()

            if records:
                return build_html_representation(records)
            else:
                return "<p>No matching records found.</p>"

    except mysql.connector.Error as e:
